 11	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
 12	import { FormattedTraceInfo, fullIDStyle } from './FormattedTraceInfo';
 13	import { KialiAppState } from '../../../store/Store';
 14	import { connect } from 'react-redux';
 15	import { isParentKiosk, kioskContextMenuAction, kioskTracingAction } from '../../Kiosk/KioskActions';
 16	import { KialiIcon } from 'config/KialiIcon';
 17	import { kebabToggleStyle } from 'styles/DropdownStyles';
 18	import { useKialiTranslation } from 'utils/I18nUtils';
 19	import { useNavigate } from 'react-router-dom-v5-compat';
 20	
 21	type ReduxProps = {
 22	  kiosk: string;
 23	};
 24	
 25	type Props = ReduxProps & {
 26	  comparisonURL?: string;
 27	  externalURL?: string;
 28	  formattedTrace: FormattedTraceInfo;
 29	  graphURL: string;
 30	  traceId?: string;
 31	};
 32	
 33	const TracingTraceTitleComponent: React.FC<Props> = (props: Props) => {
 34	  const [isKebabOpen, setIsKebabOpen] = React.useState(false);
 35	
 36	  const { t } = useKialiTranslation();
 37	  const navigate = useNavigate();
 38	
 39	  const links = [
 40	    <DropdownItem
 41	      key="view_on_graph"
 42	      onClick={() => {
 43	        if (isParentKiosk(props.kiosk)) {
 44	          kioskContextMenuAction(props.graphURL);
 45	        } else {
 46	          navigate(props.graphURL);
 47	        }
 48	      }}
 49	    >
 50	      {t('View on Graph')}
 51	    </DropdownItem>
 52	  ];
 53	
 54	  if (props.externalURL || isParentKiosk(props.kiosk)) {
 55	    links.push(
 56	      <DropdownItem
 57	        key="view_in_tracing"
 58	        onClick={e => {
 59	          if (isParentKiosk(props.kiosk)) {
 60	            e.preventDefault();
 61	            kioskTracingAction(props.externalURL ? props.externalURL : '', props.traceId);
 62	          } else {
 63	            window.open(props.externalURL, '_blank');
 64	          }
 65	        }}
 66	      >
 67	        {t('View in Tracing')} <ExternalLinkAltIcon />
 68	      </DropdownItem>
 69	    );
 70	  }
 71	
 72	  if (props.comparisonURL && !isParentKiosk(props.kiosk)) {
 73	    links.push(
 74	      <DropdownItem key="compare_with_similar_traces" onClick={() => window.open(props.comparisonURL, '_blank')}>
 75	        {t('Compare with similar traces')} <ExternalLinkAltIcon />
 76	      </DropdownItem>
 77	    );
 78	  }
 79	
 80	  return (
 81	    <CardHeader
 82	      actions={{
 83	        actions: (
 84	          <>
 85	            <span>
 86	              {`${props.formattedTrace.relativeDate()} | ${props.formattedTrace.absTime()} (${props.formattedTrace.fromNow()})`}
 87	            </span>
 88	
 89	            <Dropdown
 90	              toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 91	                <MenuToggle
 92	                  data-test="trace-details-kebab"
 93	                  ref={toggleRef}
 94	                  className={kebabToggleStyle}
 95	                  aria-label={t('Actions')}
 96	                  variant="plain"
 97	                  onClick={() => setIsKebabOpen(!isKebabOpen)}
 98	                  isExpanded={isKebabOpen}
 99	                >
100	                  <KialiIcon.KebabToggle />
101	                </MenuToggle>
102	              )}
103	              isOpen={isKebabOpen}
104	              data-test="trace-details-dropdown"
105	              onOpenChange={(isOpen: boolean) => setIsKebabOpen(isOpen)}
106	              popperProps={{ position: 'right' }}
107	            >
108	              <DropdownList>{links}</DropdownList>
109	            </Dropdown>
110	          </>
111	        ),
112	        hasNoOffset: false,
113	        className: undefined
114	      }}
115	    >
116	      <CardTitle>
117	        <span>{`${props.formattedTrace.name()} `}</span>
118	        <span className={fullIDStyle}>{props.formattedTrace.fullID()}</span>
119	      </CardTitle>
120	    </CardHeader>
121	  );
122	};
123	
124	const mapStateToProps = (state: KialiAppState): ReduxProps => {
125	  return {
126	    kiosk: state.globalState.kiosk
127	  };
128	};
129	
130	export const TracingTraceTitle = connect(mapStateToProps)(TracingTraceTitleComponent);

